const msg = $input.first().json;

// Parse "Name <email>" format
let customer_name = '';
let customer_email = '';

if (msg.From) {
  const match = msg.From.match(/(.*)<(.+)>/);
  if (match) {
    customer_name = match[1].trim();
    customer_email = match[2].trim();
  } else {
    customer_email = msg.From; // fallback
  }
}

return [{ json: {
  source: 'gmail',
  raw_subject:  msg.Subject || '(no subject)',
  raw_body:     msg.text || msg.snippet || '',
  customer_email,
  customer_name,
  raw_payload:  msg
}}];

const form = $input.first().json;
const answers = form.answers || [];
const getAnswer = (ref) => answers.find(a => a.field?.ref === ref)?.text
  || answers.find(a => a.field?.ref === ref)?.email
  || answers.find(a => a.field?.ref === ref)?.choice?.label
  || '';
return [{ json: {
  source: 'typeform',
  raw_subject:    getAnswer('subject') || 'Support Request',
  raw_body:       getAnswer('message') || '',
  customer_email: getAnswer('email') || form.hidden?.email || '',
  customer_name:  getAnswer('name') || '',
  order_number:   getAnswer('order_number') || '',
  raw_payload:    form
}}];

const payload = $input.first().json;
const msg = payload.entry?.[0]?.changes?.[0]?.value;
const message = msg?.messages?.[0];
const contact = msg?.contacts?.[0];
if (!message || message.type !== 'text') {
  return [{ json: { skip: true, reason: 'Non-text WhatsApp message — ignored' } }];
}
return [{ json: {
  source: 'whatsapp',
  raw_subject:    'WhatsApp Support Message',
  raw_body:       message.text?.body || '',
  customer_email: '',
  customer_name:  contact?.profile?.name || 'WhatsApp User',
  customer_phone: message.from || '',
  whatsapp_msg_id: message.id,
  whatsapp_phone_id: msg?.metadata?.phone_number_id,
  raw_payload:    payload
}}];

