const body = $input.first().json.body || $input.first().json;
const source = body.source || 'webhook';

// Handle Tally's nested fields array
if (body.data?.fields) {
  const fields = body.data.fields;
  const getField = (label) => fields.find(f => f.label === label);
  const resolveDropdown = (f) => {
    if (!f) return '';
    if (f.type === 'DROPDOWN' && f.options) {
      const sel = Array.isArray(f.value) ? f.value[0] : f.value;
      return f.options.find(o => o.id === sel)?.text || '';
    }
    return f.value || '';
  };
  return [{ json: {
    source: 'tally',
    raw_subject:    resolveDropdown(getField('Subject')) || 'Tally Support Request',
    raw_body:       resolveDropdown(getField('Message')) || resolveDropdown(getField('Description')) || '',
    customer_email: resolveDropdown(getField('Email')) || resolveDropdown(getField('Your email')) || '',
    customer_name:  resolveDropdown(getField('Name')) || resolveDropdown(getField('Your name')) || '',
    order_number:   resolveDropdown(getField('Order Number')) || '',
    raw_payload:    body
  }}];
}

// Generic flat JSON
return [{ json: {
  source,
  raw_subject:    body.subject || 'Support Request',
  raw_body:       body.body || body.message || body.description || '',
  customer_email: body.customer_email || body.email || '',
  customer_name:  body.customer_name || body.name || '',
  order_number:   body.order_number || '',
  raw_payload:    body
}}];

// ── NORMALISE: unify all sources into one standard ticket schema ──
const raw = $input.first().json;

// Skip signal from WhatsApp non-text messages
if (raw.skip) {
  return [{ json: { skip: true, reason: raw.reason } }];
}

// Validation
if (!raw.raw_body || raw.raw_body.trim().length < 3) {
  throw new Error(`Empty or too-short message body from ${raw.source}. Cannot create ticket.`);
}

// Generate ticket ID: SOURCE-TIMESTAMP-RANDOM
const ts = Date.now();
const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
const sourceCode = (raw.source || 'WEB').slice(0, 3).toUpperCase();
const ticketId = `${sourceCode}-${ts}-${rand}`;

// Sanitise text — strip HTML tags if from email
const stripHtml = (str) => str.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
const cleanBody = stripHtml(raw.raw_body || '').slice(0, 4000);
const cleanSubject = stripHtml(raw.raw_subject || 'Support Request').slice(0, 200);

return [{ json: {
  skip: false,
  ticket_id:      ticketId,
  source:         raw.source,
  subject:        cleanSubject,
  body:           cleanBody,
  customer_email: (raw.customer_email || '').toLowerCase().trim(),
  customer_name:  (raw.customer_name || 'Unknown').trim(),
  customer_phone: raw.customer_phone || '',
  order_number:   raw.order_number || '',
  whatsapp_msg_id:    raw.whatsapp_msg_id || '',
  whatsapp_phone_id:  raw.whatsapp_phone_id || '',
  status:         'new',
  urgency:        null,
  category:       null,
  received_at:    new Date().toISOString()
}}];

// Duplicate detection: same customer + similar subject in last 24h
const ticket = $('Normalise Ticket').item.json;
const rows = $('Read Recent Tickets').all();
const cutoff = Date.now() - 24 * 3600 * 1000;

const isDuplicate = rows.some(r => {
  const sameCustomer = r.json['Customer Email'] &&
    r.json['Customer Email'].toLowerCase() === ticket.customer_email.toLowerCase();
  const recent = new Date(r.json['Received At'] || 0).getTime() > cutoff;
  const openStatus = ['new','open','in_progress'].includes((r.json.Status || '').toLowerCase());
  return sameCustomer && recent && openStatus;
});

return [{ json: { ...ticket, is_duplicate: isDuplicate } }];

// Send acknowledgement back to customer via original channel
const ticket = $input.first().json;
const ackBody = `Hi ${ticket.customer_name || 'there'},

Thank you for reaching out. We have received your support request and assigned it ticket ID: ${ticket.ticket_id}.

We will respond within 24 hours.

If this is urgent, please reply with the word URGENT and your ticket will be prioritised.

Thank you,
Support Team`;

return [{ json: { ...ticket, ack_message: ackBody } }];

const ticket = $('Normalise Ticket').first().json;
if (!ticket.ticket_id) {
  throw new Error('Flow 2 received empty ticket — missing ticket_id. Check Flow 1 trigger.');
}
if (!ticket.body || ticket.body.trim().length < 3) {
  throw new Error(`Ticket ${ticket.ticket_id} has empty body — cannot process with AI.`);
}
// Compose the full prompt input for the AI agent
const agentInput = [
  `TICKET ID: ${ticket.ticket_id}`,
  `SOURCE: ${ticket.source}`,
  `CUSTOMER: ${ticket.customer_name} <${ticket.customer_email || ticket.customer_phone}>`,
  `SUBJECT: ${ticket.subject}`,
  ticket.order_number ? `ORDER NUMBER: ${ticket.order_number}` : '',
  `MESSAGE:\n${ticket.body}`
].filter(Boolean).join('\n');

return [{ json: { ...ticket, agent_input: agentInput } }];

const ticket = $('Validate & Prepare Agent Input').item.json;
const agentOutput = $input.first().json.output || $input.first().json;

// Parse the AI's JSON output safely
let parsed = {};
try {
  const raw = typeof agentOutput === 'string' ? agentOutput : JSON.stringify(agentOutput);
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  // If parsing fails, treat the raw output as the draft reply
  parsed = {
    category: 'general_inquiry',
    urgency: 3,
    urgency_reason: 'Could not parse structured output — defaulting to normal urgency',
    tools_used: [],
    facts_found: 'none',
    draft_reply: typeof agentOutput === 'string' ? agentOutput : 'Unable to generate response. Please review manually.',
    suggested_subject: `Re: ${ticket.subject}`,
    needs_escalation: false,
    escalation_reason: null,
    confidence: 0.0
  };
}

// Validate required fields
const urgency = parseInt(parsed.urgency) || 3;
const category = parsed.category || 'general_inquiry';
const draftReply = parsed.draft_reply || 'No draft generated.';

const N8N_BASE_URL = 'https://YOUR_N8N_DOMAIN';
const encodedData = encodeURIComponent(JSON.stringify({
  ticket_id: ticket.ticket_id,
  source: ticket.source,
  customer_email: ticket.customer_email,
  customer_name: ticket.customer_name,
  customer_phone: ticket.customer_phone,
  whatsapp_phone_id: ticket.whatsapp_phone_id,
  whatsapp_msg_id: ticket.whatsapp_msg_id,
  subject: ticket.subject,
  draft_reply: draftReply,
  suggested_subject: parsed.suggested_subject || `Re: ${ticket.subject}`,
  urgency,
  category
}));

const sendUrl     = `${N8N_BASE_URL}/webhook/support-action?action=send&data=${encodedData}`;
const editUrl     = `${N8N_BASE_URL}/webhook/support-action?action=edit&data=${encodedData}`;
const escalateUrl = `${N8N_BASE_URL}/webhook/support-action?action=escalate&data=${encodedData}`;

const urgencyEmoji = { 1: ':red_circle:', 2: ':large_yellow_circle:', 3: ':white_circle:' };
const channelLabel = { gmail: 'Email', typeform: 'Form', whatsapp: 'WhatsApp', tally: 'Tally', webhook: 'API' };

const slackMsg = [
  `${urgencyEmoji[urgency] || ':white_circle:'} *New Support Ticket* — Urgency ${urgency} | ${category.replace(/_/g, ' ')}`,
  `*Ticket:* \`${ticket.ticket_id}\` via ${channelLabel[ticket.source] || ticket.source}`,
  `*Customer:* ${ticket.customer_name}${ticket.customer_email ? ' (' + ticket.customer_email + ')' : ''}`,
  `*Subject:* ${ticket.subject}`,
  parsed.facts_found && parsed.facts_found !== 'none' ? `*Context found:* ${parsed.facts_found}` : '',
  parsed.needs_escalation ? `\n:rotating_light: *AI recommends escalation:* ${parsed.escalation_reason}` : '',
  `\n*AI Draft Reply:*\n\`\`\`${draftReply.slice(0, 800)}${draftReply.length > 800 ? '...' : ''}\`\`\``,
  `\n<${sendUrl}|Send as-is> | <${editUrl}|Edit &amp; send> | <${escalateUrl}|Escalate>`
].filter(Boolean).join('\n');

return [{
  json: {
    ...ticket,
    urgency,
    category,
    urgency_reason:    parsed.urgency_reason || '',
    tools_used:        parsed.tools_used || [],
    facts_found:       parsed.facts_found || 'none',
    draft_reply:       draftReply,
    suggested_subject: parsed.suggested_subject || `Re: ${ticket.subject}`,
    needs_escalation:  !!parsed.needs_escalation,
    escalation_reason: parsed.escalation_reason || null,
    confidence:        parsed.confidence || 0,
    slack_msg:         slackMsg,
    processed_at:      new Date().toISOString()
  }
}];

const query = $input.first().json.query || {};
const action = (query.action || '').toLowerCase();

if (!['send','edit','escalate'].includes(action)) {
  throw new Error(`Invalid support action: "${action}". Expected: send, edit, escalate`);
}
if (!query.data) {
  throw new Error('Missing ticket data in action URL');
}

let ticketData = {};
try {
  ticketData = JSON.parse(decodeURIComponent(query.data));
} catch(e) {
  throw new Error(`Could not parse ticket data from URL: ${e.message}`);
}

if (!ticketData.ticket_id) {
  throw new Error('Ticket data missing ticket_id');
}

return [{
  json: {
    action,
    ticket_id:         ticketData.ticket_id,
    source:            ticketData.source,
    customer_email:    ticketData.customer_email,
    customer_name:     ticketData.customer_name,
    customer_phone:    ticketData.customer_phone,
    whatsapp_phone_id: ticketData.whatsapp_phone_id,
    subject:           ticketData.subject,
    draft_reply:       ticketData.draft_reply,
    suggested_subject: ticketData.suggested_subject,
    urgency:           ticketData.urgency,
    category:          ticketData.category,
    actioned_at:       new Date().toISOString()
  }
}];

// Determine send channel from source
const ticket = $input.first().json;
return [{ json: { ...ticket, send_channel: ticket.source, modified: false } }];

const body = $input.first().json.body || $input.first().json;
if (!body.ticket_id || !body.reply_body) {
  throw new Error('Edit submit missing ticket_id or reply_body');
}
return [{ json: {
  action: 'send',
  modified: true,
  ticket_id:         body.ticket_id,
  source:            body.source,
  customer_email:    body.customer_email,
  customer_name:     body.customer_name,
  customer_phone:    body.customer_phone,
  whatsapp_phone_id: body.whatsapp_phone_id,
  draft_reply:       body.reply_body,
  suggested_subject: body.reply_subject || body.suggested_subject || 'Re: Your support request',
  send_channel:      body.source,
  actioned_at:       new Date().toISOString()
}}];

